#2. Use subsetting instead of a loop to rewrite the function as a single line of code

library(dplyr)
zeroes_sub &lt;- function(
    num_vec = sample(x = rep(x = c(0,1,2,3), times=10), size = 10)
){
    return(length(subset(
        x = num_vec, 
        subset = num_vec==0
        )))
}

zeroes_sub()

